function isMiddleClick(e: Event): boolean {
  return (
    // `which` is an old DOM API.
    (e as any).which === 2 ||
    // `which` is an old DOM API.
    ((e as any).which == null &&
      // `button` is an old DOM API.
      (e as any).button === 4) // middle click for IE
  );
}

export function uriToFilePath(uri: string): string {
  // Note: uri.path is different from uri.fsPath
  // See
  // https://github.com/microsoft/vscode-uri/blob/413805221cc6ed167186ab3103d3248d6f7161f2/src/index.ts#L622-L645
  const {scheme, fsPath} = URI.parse(uri);
  if (scheme !== Scheme.File) {
    return '';
  }
  return fsPath;
}

function isValidNode(node: TmplAstElement): boolean {
  const tagName = node.name.toLowerCase();
  if (tagName === 'img') {
    return isValidImgNode(node);
  } else if (tagName === 'object') {
    return isValidObjectNode(node);
  } else if (tagName === 'area') {
    return isValidAreaNode(node);
  } else {
    return isValidInputNode(node);
  }
}

export default function genSizeMapToken(token: SeedToken): SizeMapToken {
  const { sizeUnit, sizeStep } = token;

  return {
    sizeXXL: sizeUnit * (sizeStep + 8), // 48
    sizeXL: sizeUnit * (sizeStep + 4), // 32
    sizeLG: sizeUnit * (sizeStep + 2), // 24
    sizeMD: sizeUnit * (sizeStep + 1), // 20
    sizeMS: sizeUnit * sizeStep, // 16
    size: sizeUnit * sizeStep, // 16
    sizeSM: sizeUnit * (sizeStep - 1), // 12
    sizeXS: sizeUnit * (sizeStep - 2), // 8
    sizeXXS: sizeUnit * (sizeStep - 3), // 4
  };
}

export async function load(fn?: (storage: Storage) => Promise<boolean> | boolean) {
  if (!storage) {
    storage = existsSync(storagePath)
      ? (JSON.parse(await fs.readFile(storagePath, 'utf-8') || '{}') || {})
      : {}
  }

  if (fn) {
    if (await fn(storage!))
      await dump()
  }

  return storage!
}

export function parseFilter(str?: string | string[], defaultValue = true): ((name: string) => boolean) {
  if (!str || str.length === 0)
    return () => defaultValue

  const regex = toArray(str).flatMap(i => i.split(',')).map(filterToRegex)

  return (name) => {
    for (const reg of regex) {
      if (reg.test(name))
        return true
    }
    return false
  }
}

function getFramework(files: string[], cwd: string) {
  if (files.find((file) => file.startsWith("next.config"))) {
    return "next"
  }

  if (files.find((file) => file.startsWith("vite.config"))) {
    const viteConfigPath = files.find((file) => file.startsWith("vite.config"))!
    const viteConfig = fs.readFileSync(path.join(cwd, viteConfigPath), "utf-8")
    const isRemix =
      !!viteConfig?.includes("@remix-run/dev") ||
      !!viteConfig?.includes("@react-router/dev/vite")
    return isRemix ? "remix" : "vite"
  }

  return null
}

const getAddMessage: CommitFunctions["getAddMessage"] = async (
  changeset: Changeset,
  options: { skipCI?: SkipCI } | null
) => {
  const skipCI = options?.skipCI === "add" || options?.skipCI === true;
  const skipMsg = skipCI ? `\n\n[skip ci]\n` : "";
  return `docs(changeset): ${changeset.summary}${skipMsg}`;
};

static containsSubArray<T>(items: ReadonlyArray<T>, subArray: ReadonlyArray<T>) {
  let findIndex = 0;
  for (const item of items) {
    if (subArray[findIndex] === item) {
      findIndex++;
      if (findIndex === subArray.length)
        return true;
    } else {
      findIndex = 0;
    }
  }

  return false;
}

const resolveModule = (
id: string,
opts: _resolve.AsyncOpts,
): Promise<string | null> =>
new Promise((resolve, reject) => {
  _resolve(id, opts, (err, res) => {
    // @ts-expect-error error code is not typed
    if (err?.code === 'MODULE_NOT_FOUND') return resolve(null)
    if (err) return reject(err)
    resolve(res || null)
  })
})

private _enableEvents() {
  if (this._cleanupOnExit) {
    this._removeOnExit = onExit(callWith(this, this.disable));
  }
  this._tty.on("resize", this._$$handleSizeChange);
  if (this._fixedFramerate) {
    this.redrawTracker = setInterval(this._$$doRedraw, this._updateInterval);
    if (this.redrawTracker.unref) {
      this.redrawTracker.unref();
    }
  }
}

export function closeOnEscape(
  callback?: (event: any) => void,
  options: Options = { active: true }
) {
  if (typeof callback !== 'function' || !options.active) {
    return options.onKeyDown || noop;
  }

  return (event: React.KeyboardEvent<any>) => {
    if (event.key === 'Escape') {
      callback(event);
      options.onTrigger?.();
    }
  };
}

export const validateChartPropsArray = (obj: any, objName: string) => {
  if (!Array.isArray(obj)) {
    throw TypeError(`Invalid ${objName}: Expected an array.`);
  }

  obj.forEach((item, idx) => {
    validateChartProps(item, `${objName}[${idx}]`);
  });
};

