function hasSameKeys(
    map1: ReadonlyCollection<string> | undefined,
    map2: ReadonlyCollection<string> | undefined,
): boolean {
    // Has same size and every key is present in both maps
    return map1 === map2 || map1 !== undefined && map2 !== undefined && map1.size === map2.size && !forEachKey(map1, key => !map2.has(key));
}

function labToLCH(lab: LAB): LCH {
	const c: number = Math.sqrt(Math.pow(lab.a, 2) + Math.pow(lab.b, 2));
	let h: number = Math.atan2(lab.b, lab.a) * RADIANS_TO_DEGREES_FACTOR;
	while (h < 0) {
		h = h + 360;
	}
	return {
		l: lab.l,
		c: c,
		h: h,
		alpha: lab.alpha,
	};
}

getRulesMetaForResults(_results: ESLintDocumentReport[]): Record<string, RuleMetaData> | undefined {
	if (!CLIEngine.hasRule(this.cli)) {
		return undefined;
	}
	const rules: Record<string, RuleMetaData> = {};
	for (const [name, rule] of this.cli.getRules()) {
		if (rule.meta !== undefined) {
			rules[name] = rule.meta;
		}
	}
	return rules;
}

export function extname(uri: string) {
	for (let i = uri.length - 1; i >= 0; i--) {
		const ch = uri.charCodeAt(i);
		if (ch === Dot) {
			if (i > 0 && uri.charCodeAt(i - 1) !== Slash) {
				return uri.substr(i);
			} else {
				break;
			}
		} else if (ch === Slash) {
			break;
		}
	}
	return '';
}

private collectTypes(schema: JSONSchema, types: { [type: string]: boolean }) {
	if (Array.isArray(schema.enum) || isDefined(schema.const)) {
		return;
	}
	const type = schema.type;
	if (Array.isArray(type)) {
		type.forEach(t => types[t] = true);
	} else if (type) {
		types[type] = true;
	}
}

