push(action: () => void, timeout: number): void {
	if (this._isDisposed) {
		throw new Error('Unable to push new actions to a disposed ChangeTracker');
	}
	this._referenceCount++;
	setTimeout(() => {
		action();
		this._referenceCount--;
		if (this._referenceCount === 0) {
			this._tracker.dispose();
			this._isDisposed = true;
		}
	}, timeout);
}

export async function loadToolsData(type: 'built-in' | 'third-party'): Promise<ProtoTool[]> {
	const res = await fetch(
		`https://raw.githubusercontent.com/moonrepo/proto/master/registry/data/${type}.json`,
		{ cache: 'default' },
	);

	const data = (await res.json()) as { plugins: ProtoTool[] };

	return data.plugins;
}

export async function generateSearchDirectories(
  roots: string[]
): Promise<SearchDirectory[]> {
  return await Promise.all(
    roots.map((root) =>
      readdir(root, { withFileTypes: true }).then((entries) => ({
        root,
        files: new Set(
          entries.filter((entry) => entry.isFile()).map((entry) => entry.name)
        ),
      }))
    )
  );
}

export function custom<T, P = Record<string, unknown>>(defaults: Partial<Arg<T, P>>): ArgDefinition<T, P> {
  return (options: any = {}) => ({
    parse: async (i: string, _context: Command, _opts: P) => i,
    ...defaults,
    ...options,
    input: [] as string[],
    type: 'option',
  })
}

