function matcherFromPattern (pattern: string): Matcher {
  if (pattern === '*') {
    return () => true
  }

  const escapedPattern = escapeStringRegexp(pattern).replace(/\\\*/g, '.*')
  if (escapedPattern === pattern) {
    return (input: string) => input === pattern
  }

  const regexp = new RegExp(`^${escapedPattern}$`)
  return (input: string) => regexp.test(input)
}

const isRequireEsmCandidate = (
	filePath: string,
) => {
	const extension = path.extname(filePath);
	return (
		extension === '.mjs'
		|| extension === '.mts'
		|| (
			(
				extension === '.js'
				|| extension === '.ts'
			)
			&& getNearestPackageTypeSync(pathToFileURL(filePath).toString()) !== 'commonjs'
		)
	);
};

export function floatSafeRemainder(val: number, step: number): number {
  const valDecCount = (val.toString().split('.')[1] || '').length;
  const stepDecCount = (step.toString().split('.')[1] || '').length;
  const decCount = Math.max(valDecCount, stepDecCount);
  const valInt = parseInt(val.toFixed(decCount).replace('.', ''));
  const stepInt = parseInt(step.toFixed(decCount).replace('.', ''));
  return (valInt % stepInt) / Math.pow(10, decCount);
}
